mapper.select:
SELECT TOP 500 Row_Number() OVER (Order By TF.FltpCode, TF.FileName) AS RNUM ,TF.FileID ,0 AS CHK ,TF.InstanceNo AS DocumentID ,'' AS DocCategory ,TF.LinkType ,TF.FileName ,TF.FltpCode As FltpCode ,TF.FileFormat ,TF.FileRealName ,TF.FileSize ,TF.FileMgt ,TF.RegMemberID ,CONVERT(CHAR(10),CONVERT(datetime,TF.CreationTime),21) AS CreationTime ,CONVERT(CHAR(10),CONVERT(datetime,TF.LastUpdated),21) AS LastUpdated ,TF.LastUser ,TF.Version ,TF.DownCNT ,ISNULL(TM.Name, '') WriteUserNM ,TDFT.FilePath+TF.FileName AS SysFile ,TDFT.FilePath+TF.FileRealName AS OrigFile ,TDFT.FilePath ,TF.FilePath AS ExtFileURL ,TD.Name AS FltpName ,TDFT.fileOption ,'' As ItemTypeCode ,( select t2.name from XBOLTADM.TB_MEMBER t1 left outer join XBOLTADM.TB_TEAM_TXT t2 on t1.teamId = t2.teamId where t1.memberId = TF.RegMemberID and t2.LanguageID = #{languageID} ) as TeamName ,'' AS Path ,'' AS ClassCode ,TL.LanguageCode FROM XBOLTAPP.PIM_INSTANCE_FILE TF LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM ON TF.RegMemberID = TM.MemberID LEFT OUTER JOIN XBOLTADM.TB_FLTP TDFT ON TDFT.FltpCode = TF.FltpCode LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD ON TD.TypeCode = TF.FltpCode AND TD.LanguageID = #{languageID} And TD.Category ='FLTP' Left Outer Join XBOLTADM.TB_LANGUAGE TL On TL.LanguageID = TF.LanguageID Where InstanceNo = #{instanceNo} And instanceClass = #{instanceClass}
AND TF.fileRealName like N'%'+#{searchValue}+'%'
AND TF.Description like N'%'+#{searchValue}+'%'

Select ISNULL(TDFT.FilePath, TF.FilePath) AS FilePath From XBOLTADM.TB_FLTP TDFT
Left Outer Join XBOLTAPP.PIM_INSTANCE_FILE TF ON TF.FltpCode = TDFT.FltpCode
Where TF.FileID = #{fileID}
